<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bots</title>
<style>
  body {
    background: #1a1a2e;
    color: #fff;
    font-family: system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    margin: 0;
    padding: 20px;
  }
  #hud {
    display: flex;
    gap: 20px;
    align-items: center;
    margin-bottom: 15px;
    background: #16213e;
    padding: 10px 20px;
    border-radius: 8px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.3);
  }
  .stat { font-size: 1.1rem; font-weight: 500; }
  #reset {
    padding: 8px 16px;
    background: #e94560;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: bold;
    font-size: 1rem;
    transition: background 0.2s;
  }
  #reset:hover { background: #ff5c77; }
  #maze {
    width: 420px;
    height: 420px;
    border: 3px solid #16213e;
    border-radius: 6px;
    box-shadow: 0 8px 16px rgba(0,0,0,0.5);
    background: #000;
  }
</style>
</head>
<body>
  <div id="hud">
    <div class="stat">Completed: <span id="completed">0</span> / 24</div>
    <div class="stat">Time: <span id="timer">0.0</span>s</div>
    <button id="reset">Reset Game</button>
  </div>
  <canvas id="maze" width="420" height="420"></canvas>

  <script>
    const COLS = 21;
    const ROWS = 21;
    const CELL = 20;
    const STEP_MS = 50;
    const NUM_BOTS = 24;

    let grid = [];
    const spawn = {x: 1, y: 1};
    const exit = {x: COLS - 2, y: ROWS - 2};
    let bots = [];
    let completedCount = 0;
    let ticks = 0;

    const canvas = document.getElementById('maze');
    const ctx = canvas.getContext('2d');

    function generateMaze() {
      grid = [];
      for (let y = 0; y < ROWS; y++) {
        grid[y] = [];
        for (let x = 0; x < COLS; x++) {
          grid[y][x] = 1;
        }
      }
      let stack = [];
      grid[spawn.y][spawn.x] = 0;
      stack.push(spawn);
      let dirs = [[0,-2],[0,2],[-2,0],[2,0]];
      while (stack.length > 0) {
        let curr = stack[stack.length - 1];
        let neighbors = [];
        for (let d of dirs) {
          let nx = curr.x + d[0];
          let ny = curr.y + d[1];
          if (nx > 0 && nx < COLS-1 && ny > 0 && ny < ROWS-1 && grid[ny][nx] === 1) {
            neighbors.push({x: nx, y: ny, wx: curr.x + d[0]/2, wy: curr.y + d[1]/2});
          }
        }
        if (neighbors.length > 0) {
          let next = neighbors[Math.floor(Math.random() * neighbors.length)];
          grid[next.wy][next.wx] = 0;
          grid[next.y][next.x] = 0;
          stack.push({x: next.x, y: next.y});
        } else {
          stack.pop();
        }
      }
      // Braiding: remove some internal walls to create loops
      for (let y = 1; y < ROWS-1; y++) {
        for (let x = 1; x < COLS-1; x++) {
          if (grid[y][x] === 1) {
            let horiz = grid[y][x-1] === 0 && grid[y][x+1] === 0;
            let vert = grid[y-1][x] === 0 && grid[y+1][x] === 0;
            if (horiz || vert) {
              if (Math.random() < 0.25) {
                grid[y][x] = 0;
              }
            }
          }
        }
      }
      grid[spawn.y][spawn.x] = 0;
      grid[exit.y][exit.x] = 0;
    }

    function computeDistances(src) {
      let dist = [];
      for (let y = 0; y < ROWS; y++) {
        dist[y] = [];
        for (let x = 0; x < COLS; x++) {
          dist[y][x] = Infinity;
        }
      }
      let q = [src];
      dist[src.y][src.x] = 0;
      let head = 0;
      let dirs = [[0,-1],[0,1],[-1,0],[1,0]];
      while (head < q.length) {
        let curr = q[head++];
        for (let d of dirs) {
          let nx = curr.x + d[0];
          let ny = curr.y + d[1];
          if (nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS && grid[ny][nx] === 0) {
            if (dist[ny][nx] === Infinity) {
              dist[ny][nx] = dist[curr.y][curr.x] + 1;
              q.push({x: nx, y: ny});
            }
          }
        }
      }
      return dist;
    }

    function constructPath(start, dist) {
      let path = [start];
      let curr = start;
      let dirs = [[0,-1],[0,1],[-1,0],[1,0]];
      while (!(curr.x === exit.x && curr.y === exit.y)) {
        let neighbors = [];
        for (let d of dirs) {
          let nx = curr.x + d[0];
          let ny = curr.y + d[1];
          if (nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS && grid[ny][nx] === 0) {
            if (dist[ny][nx] === dist[curr.y][curr.x] - 1) {
              neighbors.push({x: nx, y: ny});
            }
          }
        }
        let next = neighbors[Math.floor(Math.random() * neighbors.length)];
        path.push(next);
        curr = next;
      }
      return path;
    }

    function reset() {
      generateMaze();
      let dist = computeDistances(exit);
      bots = [];
      for (let i = 0; i < NUM_BOTS; i++) {
        let path = constructPath(spawn, dist);
        bots.push({
          id: i,
          x: spawn.x,
          y: spawn.y,
          path: path,
          pathIndex: 0,
          completed: false
        });
      }
      completedCount = 0;
      ticks = 0;
      window.game.bots = bots;
      window.game.completed = 0;
      window.game.elapsedMs = 0;
      updateHUD();
      render();
    }

    function tick(n) {
      for (let s = 0; s < n; s++) {
        for (let i = 0; i < bots.length; i++) {
          let bot = bots[i];
          if (!bot.completed) {
            if (bot.pathIndex < bot.path.length - 1) {
              bot.pathIndex++;
              bot.x = bot.path[bot.pathIndex].x;
              bot.y = bot.path[bot.pathIndex].y;
            }
            if (bot.pathIndex === bot.path.length - 1) {
              bot.completed = true;
              completedCount++;
            }
          }
        }
        ticks++;
      }
      window.game.completed = completedCount;
      window.game.elapsedMs = ticks * STEP_MS;
      updateHUD();
    }

    function updateHUD() {
      document.getElementById('completed').textContent = completedCount;
      document.getElementById('timer').textContent = (ticks * STEP_MS / 1000).toFixed(1);
    }

    function render() {
      for (let y = 0; y < ROWS; y++) {
        for (let x = 0; x < COLS; x++) {
          if (grid[y][x] === 1) {
            ctx.fillStyle = '#2c3e50';
          } else if (x === spawn.x && y === spawn.y) {
            ctx.fillStyle = '#2ecc71';
          } else if (x === exit.x && y === exit.y) {
            ctx.fillStyle = '#e74c3c';
          } else {
            ctx.fillStyle = '#ecf0f1';
          }
          ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
        }
      }
      bots.forEach((bot, i) => {
        let cx = bot.x * CELL + CELL / 2;
        let cy = bot.y * CELL + CELL / 2;
        let ox = (i % 5 - 2) * 2;
        let oy = (Math.floor(i / 5) - 2) * 2;
        ctx.beginPath();
        ctx.arc(cx + ox, cy + oy, 4, 0, Math.PI * 2);
        ctx.fillStyle = `hsl(${i * 15}, 80%, 50%)`;
        ctx.fill();
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 1;
        ctx.stroke();
      });
    }

    window.game = {
      bots: [],
      completed: 0,
      elapsedMs: 0,
      tick: tick,
      reset: reset
    };

    document.getElementById('reset').addEventListener('click', reset);

    let lastTime = performance.now();
    let accumulator = 0;
    function loop(time) {
      let dt = time - lastTime;
      lastTime = time;
      if (dt > 1000) dt = 1000;
      accumulator += dt;
      if (accumulator >= STEP_MS) {
        let steps = Math.floor(accumulator / STEP_MS);
        accumulator -= steps * STEP_MS;
        tick(steps);
      }
      render();
      requestAnimationFrame(loop);
    }

    reset();
    requestAnimationFrame(loop);
  </script>
</body>
</html>
